  // when (1 << K) > C, because:
  //   X = (X / C) * C + (X % C)
  //   (X / C) << K | (X % C) = (X / C) * (1 << K) + (X % C)
  //                          = (X / C) * (1 << K) + X - (X / C) * C
  //                          = (X / C) * ((1 << K) - C) + X
  // For the 'or' to be equivalent to 'add', we need (1 << K) > C so that
  // (X / C) << K and (X % C) don't have overlapping bits.
  {
    Value *X, *DivVal, *RemVal;
    const APInt *DivC, *ShiftAmt;
    // Match: or (shl (udiv X, C), K), (urem X, C)
    bool MatchedUnsigned =
        match(&I, m_c_DisjointOr(
                      m_OneUse(m_Shl(m_OneUse(m_UDiv(m_Value(DivVal), m_APInt(DivC))),
                                     m_APInt(ShiftAmt))),
