        match(&I, m_c_DisjointOr(
                      m_OneUse(m_URem(m_Value(DivVal), m_APInt(DivC))),
                      m_OneUse(m_Shl(m_OneUse(m_UDiv(m_Specific(DivVal), m_Specific(DivC))),
                                     m_APInt(ShiftAmt)))));
    if (MatchedUnsigned) {
      // Check that (1 << K) > C, i.e., the shift produces non-overlapping bits
      APInt ShiftedOne = APInt::getOneBitSet(ShiftAmt->getBitWidth(), ShiftAmt->getZExtValue());
      if (ShiftedOne.ugt(*DivC) && !DivC->isZero()) {
