      // Match Op1 as urem X, RemC
      if (!match(Op1, m_URem(m_Specific(X), m_APInt(&DivC2))))
        return false;
      // Check that divisors match
      if (*DivC != DivC2)
        return false;
      DivC1 = *DivC;
      return true;
    };

    bool Matched = MatchUDivURemPattern(Op0, Op1) || MatchUDivURemPattern(Op1, Op0);
    if (Matched && !DivC1.isZero()) {
